//! Emit `keymap.c` from a [`CanonicalLayout`].
//!
//! Output shape:
//!
//! ```c
//! // SPDX-License-Identifier: MIT
//! // Generated by oryx-bench. Do not edit by hand.
//! #include QMK_KEYBOARD_H
//! #include "_features.h"   // declarations from generate::features
//!
//! enum layers { MAIN, SYM_NUM, BRD_SYS, GAMING };
//!
//! const uint16_t PROGMEM keymaps[][MATRIX_ROWS][MATRIX_COLS] = {
//!   [MAIN] = LAYOUT_voyager(
//!       KC_DELETE, KC_1, ..., KC_BSPC
//!   ),
//!   [SYM_NUM] = LAYOUT_voyager(...),
//!   ...
//! };
//! ```
//!
//! Bindings are emitted via [`emit_action`] which translates each
//! [`CanonicalAction`] into a single QMK keycode token. Layer references
//! resolve to the sanitized layer ident from the [`LayerTable`].

use std::fmt::Write;

use crate::schema::canonical::{CanonicalAction, CanonicalLayer, CanonicalLayout, LayerRef};
use crate::schema::geometry::Geometry;

use super::{CustomKeycodeTable, LayerTable, TapDanceTable};

/// Top-level entry point — produces the full keymap.c source string.
///
/// `keymap.c` only owns the per-layer `LAYOUT_<board>(...)` arrays and
/// the `enum layers` definition. The `enum custom_keycodes` and the
/// `process_record_user` dispatch live in `_features.h` / `_features.c`
/// so both translation units see the same symbols.
pub fn emit_keymap_c(
    layout: &CanonicalLayout,
    geom: &dyn Geometry,
    layers: &LayerTable,
    custom_keycodes: &CustomKeycodeTable,
    tap_dances: &TapDanceTable,
) -> anyhow::Result<String> {
    let mut out = String::new();
    out.push_str("// SPDX-License-Identifier: MIT\n");
    out.push_str("// Generated by oryx-bench. Do not edit by hand.\n");
    out.push_str("#include QMK_KEYBOARD_H\n");
    out.push_str("#include \"_features.h\"\n\n");

    out.push_str(&emit_layers_enum(layout, layers));
    out.push('\n');

    out.push_str(&emit_keymaps_array(
        layout,
        geom,
        layers,
        custom_keycodes,
        tap_dances,
    )?);

    Ok(out)
}

fn emit_layers_enum(layout: &CanonicalLayout, layers: &LayerTable) -> String {
    let mut out = String::from("enum layers {\n");
    let mut sorted: Vec<&CanonicalLayer> = layout.layers.iter().collect();
    sorted.sort_by_key(|l| l.position);
    for layer in sorted {
        let ident = layers
            .get(&layer.name)
            .map(|e| e.ident.clone())
            .unwrap_or_else(|| layer.name.clone());
        let _ = writeln!(out, "    {ident},");
    }
    out.push_str("};\n");
    out
}

fn emit_keymaps_array(
    layout: &CanonicalLayout,
    geom: &dyn Geometry,
    layers: &LayerTable,
    custom_keycodes: &CustomKeycodeTable,
    tap_dances: &TapDanceTable,
) -> anyhow::Result<String> {
    let mut out = String::from("const uint16_t PROGMEM keymaps[][MATRIX_ROWS][MATRIX_COLS] = {\n");
    let mut sorted: Vec<&CanonicalLayer> = layout.layers.iter().collect();
    sorted.sort_by_key(|l| l.position);

    let qmk_order = geom.qmk_arg_order();
    debug_assert_eq!(
        qmk_order.len(),
        geom.matrix_key_count(),
        "qmk_arg_order length must match matrix_key_count"
    );

    for layer in sorted {
        let ident = layers
            .get(&layer.name)
            .map(|e| e.ident.clone())
            .ok_or_else(|| {
                anyhow::anyhow!(
                    "layer '{}' is missing from the layer table — this is a canonicalization bug",
                    layer.name
                )
            })?;
        let _ = writeln!(out, "    [{ident}] = {}(", geom.layout_macro());

        // QMK's LAYOUT_<board> macro takes positional args in physical
        // order (interleaved left/right per row, thumbs at the end).
        // Oryx's keys[] array is in serialization order (left rows then
        // left thumb then right rows then right thumb). We must permute
        // canonical → QMK order before emitting, otherwise every key
        // ends up at the wrong physical position.
        let mut cells: Vec<String> = Vec::with_capacity(qmk_order.len());
        for &canonical_idx in qmk_order {
            let cell = match layer.keys.get(canonical_idx) {
                Some(k) => {
                    // If this key has a tap-dance entry, emit TD(n).
                    if let Some(td) = tap_dances.iter().find(|td| {
                        td.layer_position == layer.position && td.key_index == canonical_idx
                    }) {
                        format!("TD({})", td.td_index)
                    } else {
                        emit_key(k, layers, custom_keycodes)?
                    }
                }
                None => "KC_NO".to_string(),
            };
            cells.push(cell);
        }
        for chunk in cells.chunks(6) {
            let _ = writeln!(out, "        {},", chunk.join(", "));
        }
        out.push_str("    ),\n");
    }
    out.push_str("};\n");
    Ok(out)
}

/// Single-key emission.
///
/// `oryx_key_to_canonical` already collapses the common combinations
/// (`tap=KC_X + hold=MO(N) → LT`, `tap=KC_X + hold=Modifier → ModTap`),
/// so most keys reach this function with either tap-only or hold-only.
/// For any remaining tap+hold case we synthesize `LT`/`ModTap` here as a
/// safety net so the keymap output is never silently lossy.
pub fn emit_key(
    key: &crate::schema::canonical::CanonicalKey,
    layers: &LayerTable,
    custom_keycodes: &CustomKeycodeTable,
) -> anyhow::Result<String> {
    use crate::schema::canonical::CanonicalAction;

    // Defensive: double_tap keys should be handled by the tap-dance table
    // lookup in emit_keymaps_array, never reach emit_key directly.
    if key.double_tap.is_some() {
        anyhow::bail!(
            "internal error: emit_key called for a key with double_tap set — \
             this should have been handled by the tap-dance table lookup"
        );
    }

    match (&key.tap, &key.hold) {
        (Some(tap_a), Some(hold_a)) => {
            // Defensive collapse for any tap+hold pair the canonical pass missed.
            let synthetic = match (tap_a, hold_a) {
                (CanonicalAction::Keycode(_), CanonicalAction::Mo { layer }) => {
                    CanonicalAction::Lt {
                        layer: layer.clone(),
                        tap: Box::new(tap_a.clone()),
                    }
                }
                (CanonicalAction::Keycode(_), CanonicalAction::Modifier(m)) => {
                    CanonicalAction::ModTap {
                        mod_: m.clone(),
                        tap: Box::new(tap_a.clone()),
                    }
                }
                _ => tap_a.clone(),
            };
            emit_action(&synthetic, layers, custom_keycodes)
        }
        (Some(action), None) => emit_action(action, layers, custom_keycodes),
        (None, Some(action)) => emit_action(action, layers, custom_keycodes),
        (None, None) => Ok("KC_NO".to_string()),
    }
}

/// Translate a single [`CanonicalAction`] to its QMK C token.
///
/// Returns `Err` if the action references a layer that's not in the
/// table — that can only happen if the canonical layout is
/// inconsistent with itself (e.g. an `MO(Sym+Num)` on a layout that
/// doesn't have a `Sym+Num` layer) and the right response is to fail
/// the build with a clear message instead of emitting an invalid C
/// identifier. Unknown keycodes are handled elsewhere by
/// [`Keycode::Other`] which preserves the original string verbatim.
pub fn emit_action(
    action: &CanonicalAction,
    layers: &LayerTable,
    custom_keycodes: &CustomKeycodeTable,
) -> anyhow::Result<String> {
    Ok(match action {
        CanonicalAction::Keycode(kc) => kc.canonical_name().into_owned(),
        CanonicalAction::Modifier(m) => format!("KC_{}", m.canonical_name()),
        CanonicalAction::Mo { layer } => format!("MO({})", resolve_layer(layer, layers)?),
        CanonicalAction::Tg { layer } => format!("TG({})", resolve_layer(layer, layers)?),
        CanonicalAction::To { layer } => format!("TO({})", resolve_layer(layer, layers)?),
        CanonicalAction::Tt { layer } => format!("TT({})", resolve_layer(layer, layers)?),
        CanonicalAction::Df { layer } => format!("DF({})", resolve_layer(layer, layers)?),
        CanonicalAction::Lt { layer, tap } => format!(
            "LT({}, {})",
            resolve_layer(layer, layers)?,
            emit_action(tap, layers, custom_keycodes)?
        ),
        CanonicalAction::ModTap { mod_, tap } => format!(
            "{}_T({})",
            mod_.canonical_name(),
            emit_action(tap, layers, custom_keycodes)?
        ),
        CanonicalAction::Modified { mods, base } => {
            // Render as nested QMK modifier macros: `LCTL(LSFT(KC_TAB))`.
            let mut out = emit_action(base, layers, custom_keycodes)?;
            for m in mods.iter().rev() {
                out = format!("{}({})", m.canonical_name(), out);
            }
            out
        }
        CanonicalAction::Custom(n) => {
            // If features.toml has a matching `[[macros]]` entry, emit
            // the corresponding `CK_<name>` enum value. Otherwise emit
            // the QMK-native `USER<nn>` symbol — QMK declares these in
            // its `keycodes.h`, so a Tier 2 `.zig`/`.c` overlay can
            // dispatch on them without needing our generated enum.
            //
            // The previous fallback `KC_NO /* missing CK for ... */`
            // silently replaced the key with "does nothing" which
            // meant pressing the key in a layout that relied on Tier 2
            // handled USERnn produced no feedback at all; that was a
            // latent correctness bug behind a code comment.
            //
            // Defense in depth: both parsers reject `USER<nn>` for
            // n > MAX_USER_KEYCODE_SLOT (32 slots, USER00..USER31).
            // If a `Custom(n)` with n out-of-range somehow reaches us
            // anyway, fail loudly here rather than emit an
            // undeclared QMK identifier that would surface as a
            // confusing link error inside the docker build.
            use crate::schema::canonical::MAX_USER_KEYCODE_SLOT;
            if (*n as u32) > MAX_USER_KEYCODE_SLOT {
                return Err(anyhow::anyhow!(
                    "custom keycode USER{n:02} is out of range — QMK only supports USER00..USER{MAX_USER_KEYCODE_SLOT:02}. \
                     Either reduce the slot number in your visual layout or define a [[macros]] entry mapping it to a CK_<name>."
                ));
            }
            let slot = format!("USER{:02}", n);
            custom_keycodes
                .get(&slot)
                .map(|e| e.ident.clone())
                .unwrap_or(slot)
        }
        CanonicalAction::Transparent => "KC_TRNS".to_string(),
        CanonicalAction::None => "KC_NO".to_string(),
    })
}

/// Resolve a [`LayerRef`] to a sanitized C identifier.
///
/// Returns `Err` if the reference doesn't match any layer in the
/// table. Silently falling back to the raw user-facing name (which
/// may contain `+`, spaces, etc.) used to mask a real bug in the
/// canonical layout — the QMK compile would fail with a confusing
/// error like `'Sym+Num' undeclared` deep inside keymap.c, and the
/// user had no path back to the root cause.
fn resolve_layer(r: &LayerRef, layers: &LayerTable) -> anyhow::Result<String> {
    match r {
        LayerRef::Name(n) => layers.get(n).map(|e| e.ident.clone()).ok_or_else(|| {
            anyhow::anyhow!(
                "unknown layer '{n}' — define it in the visual layout or fix the reference"
            )
        }),
        LayerRef::Index(i) => layers
            .values()
            .find(|e| e.position == *i)
            .map(|e| e.ident.clone())
            .ok_or_else(|| {
                anyhow::anyhow!(
                    "unknown layer index {i} — no layer in the canonical layout has this position"
                )
            }),
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::generate::{LayerEntry, LayerTable, TapDanceTable};
    use crate::schema::canonical::{CanonicalKey, CanonicalLayer};
    use crate::schema::geometry;
    use crate::schema::keycode::{Keycode, Modifier};

    fn one_layer_table() -> LayerTable {
        let mut t = LayerTable::new();
        t.insert(
            "Main".into(),
            LayerEntry {
                ident: "MAIN".into(),
                position: 0,
            },
        );
        t.insert(
            "SymNum".into(),
            LayerEntry {
                ident: "SYMNUM".into(),
                position: 1,
            },
        );
        t
    }

    #[test]
    fn emit_action_keycode() {
        let layers = one_layer_table();
        let custom = CustomKeycodeTable::new();
        let out = emit_action(&CanonicalAction::Keycode(Keycode::KcA), &layers, &custom).unwrap();
        assert_eq!(out, "KC_A");
    }

    #[test]
    fn emit_action_lt_with_layer_name() {
        let layers = one_layer_table();
        let custom = CustomKeycodeTable::new();
        let out = emit_action(
            &CanonicalAction::Lt {
                layer: LayerRef::Name("SymNum".into()),
                tap: Box::new(CanonicalAction::Keycode(Keycode::KcBspc)),
            },
            &layers,
            &custom,
        )
        .unwrap();
        assert_eq!(out, "LT(SYMNUM, KC_BSPC)");
    }

    #[test]
    fn emit_action_mod_tap() {
        let layers = one_layer_table();
        let custom = CustomKeycodeTable::new();
        let out = emit_action(
            &CanonicalAction::ModTap {
                mod_: Modifier::Lsft,
                tap: Box::new(CanonicalAction::Keycode(Keycode::KcA)),
            },
            &layers,
            &custom,
        )
        .unwrap();
        assert_eq!(out, "LSFT_T(KC_A)");
    }

    #[test]
    fn emit_action_mo_resolves_index_to_ident() {
        let layers = one_layer_table();
        let custom = CustomKeycodeTable::new();
        let out = emit_action(
            &CanonicalAction::Mo {
                layer: LayerRef::Index(1),
            },
            &layers,
            &custom,
        )
        .unwrap();
        assert_eq!(out, "MO(SYMNUM)");
    }

    #[test]
    fn emit_action_unknown_layer_name_errors() {
        let layers = one_layer_table();
        let custom = CustomKeycodeTable::new();
        let err = emit_action(
            &CanonicalAction::Mo {
                layer: LayerRef::Name("DoesNotExist".into()),
            },
            &layers,
            &custom,
        )
        .unwrap_err();
        assert!(
            err.to_string().contains("unknown layer 'DoesNotExist'"),
            "unexpected: {err}"
        );
    }

    #[test]
    fn emit_action_unknown_layer_index_errors() {
        let layers = one_layer_table();
        let custom = CustomKeycodeTable::new();
        let err = emit_action(
            &CanonicalAction::Mo {
                layer: LayerRef::Index(99),
            },
            &layers,
            &custom,
        )
        .unwrap_err();
        assert!(
            err.to_string().contains("unknown layer index 99"),
            "unexpected: {err}"
        );
    }

    #[test]
    fn emit_action_custom_falls_back_to_user_literal() {
        // When features.toml has no matching [[macros]] entry,
        // Custom(0) becomes USER00 — a QMK-native symbol the user's
        // Tier 2 code can dispatch on.
        let layers = one_layer_table();
        let custom = CustomKeycodeTable::new();
        let out = emit_action(&CanonicalAction::Custom(5), &layers, &custom).unwrap();
        assert_eq!(out, "USER05");
    }

    #[test]
    fn emit_action_custom_at_max_slot_succeeds() {
        // USER31 is the highest QMK-supported user-keycode slot.
        let layers = one_layer_table();
        let custom = CustomKeycodeTable::new();
        let out = emit_action(&CanonicalAction::Custom(31), &layers, &custom).unwrap();
        assert_eq!(out, "USER31");
    }

    #[test]
    fn emit_action_custom_above_max_slot_errors() {
        // QMK only supports 32 slots (USER00..USER31). A Custom(n)
        // with n > 31 must fail loudly at codegen rather than emit
        // an undeclared identifier and produce a confusing QMK link
        // error.
        let layers = one_layer_table();
        let custom = CustomKeycodeTable::new();
        let err = emit_action(&CanonicalAction::Custom(32), &layers, &custom).unwrap_err();
        let msg = err.to_string();
        assert!(msg.contains("USER32"), "expected USER32 in error: {msg}");
        assert!(
            msg.contains("USER31") || msg.contains("32 slots") || msg.contains("USER00"),
            "expected limit hint in error: {msg}"
        );
    }

    #[test]
    fn emit_keymap_c_includes_layout_macro() {
        let layout = CanonicalLayout {
            geometry: "voyager".into(),
            title: "test".into(),
            layers: vec![CanonicalLayer {
                name: "Main".into(),
                position: 0,
                keys: vec![CanonicalKey::default(); 52],
            }],
            combos: Vec::new(),
            config: Default::default(),
        };
        let geom = geometry::get("voyager").unwrap();
        let layers = one_layer_table();
        let custom = CustomKeycodeTable::new();
        let out = emit_keymap_c(&layout, geom, &layers, &custom, &TapDanceTable::new()).unwrap();
        assert!(out.contains("LAYOUT_voyager"));
        assert!(out.contains("enum layers"));
        assert!(out.contains("[MAIN] = LAYOUT_voyager"));
    }
}
